import React, { useState } from "react";
import ReactDOM from "react-dom/client";
import { ArrowRight, ArrowLeft } from "lucide-react";
import "./Biscuits.css";

// --- Simulating CSS Modules ---

const commonStyles = {
  container: "layout_container",
  section: "layout_section",
  btnGhost: "ui_btn ui_btnGhost",
  headerWrapper: "Header_wrapper",
  headerSubtitle: "Header_subtitle",
  headerTitle: "Header_title",
};

// --- Components ---

const Biscuits = () => {
  const styles = {
    navBar: "Catalog_navBar",
    filterWrapper: "Catalog_filterWrapper",
    filterBtn: "Catalog_filterBtn",
    filterBtnActive: "Catalog_filterBtnActive",
    grid: "Catalog_grid",
    card: "Catalog_card",
    imgContainer: "Catalog_imgContainer",
    img: "Catalog_img",
    info: "Catalog_info",
    name: "Catalog_name",
    desc: "Catalog_desc",
  };

  const [activeFilter, setActiveFilter] = useState("marshmallow");

  const filters = [
    { id: "marshmallow", label: "بسكويت مع مارشميلو" },
    { id: "coated", label: "بسكويت مغطس" },
    { id: "jelly", label: "بسكويت مع الجيلي" },
  ];

  const products = [
    {
      id: 1,
      name: "هاغي باف",
      category: "marshmallow",
      desc: "مارشميلو غني وطري يذوب في فمك",
      img: "https://images.unsplash.com/photo-1627485937980-221c88ac04f9?q=80&w=800&auto=format&fit=crop",
    },
    {
      id: 2,
      name: "بيسكو موش",
      category: "marshmallow",
      desc: "مزيج ساحر من البسكويت المقرمش والمارشميلو",
      img: "https://images.unsplash.com/photo-1590080875913-1d5677995f7c?q=80&w=800&auto=format&fit=crop",
    },
    {
      id: 3,
      name: "هستيريا",
      category: "coated",
      desc: "شوكولاتة فاخرة تغطي كل قضمة",
      img: "https://images.unsplash.com/photo-1621236378699-8597faf6a176?q=80&w=800&auto=format&fit=crop",
    },
    {
      id: 4,
      name: "أوباليز",
      category: "coated",
      desc: "تغطية غنية بالحليب لطعم لا يقاوم",
      img: "https://images.unsplash.com/photo-1606312619070-d48b7065e1b0?q=80&w=800&auto=format&fit=crop",
    },
    {
      id: 5,
      name: "بيسكو جيل",
      category: "jelly",
      desc: "انفجار نكهة الفواكه الطبيعية مع كل قطعة",
      img: "https://images.unsplash.com/photo-1558961363-fa8fdf82db35?q=80&w=800&auto=format&fit=crop",
    },
  ];

  const filteredProducts = products.filter((p) => p.category === activeFilter);

  const goBack = () => {
    window.location.href = "index.html";
  };

  return (
    <div style={{ minHeight: "100vh", backgroundColor: "#fff" }}>
      <div className={commonStyles.container}>
        {/* Navigation Bar */}
        <div className={styles.navBar}>
          <button onClick={goBack} className={commonStyles.btnGhost}>
            <ArrowRight size={20} style={{ marginLeft: "0.5rem" }} /> العودة
            للرئيسية
          </button>
          <img src="/vite.svg" alt="Biscoza" style={{ height: "40px" }} />
          <div style={{ width: "100px" }}></div>{" "}
          {/* Spacer for center alignment */}
        </div>

        <SectionHeader subtitle="عالم بيسكوزا" title="تصفح منتجات البسكويت" />

        {/* Filters */}
        <div className={styles.filterWrapper}>
          {filters.map((filter) => (
            <button
              key={filter.id}
              className={`${styles.filterBtn} ${
                activeFilter === filter.id ? styles.filterBtnActive : ""
              }`}
              onClick={() => setActiveFilter(filter.id)}
            >
              {filter.label}
            </button>
          ))}
        </div>

        {/* Grid */}
        <div className={styles.grid}>
          {filteredProducts.map((product) => (
            <div key={product.id} className={styles.card}>
              <div className={styles.imgContainer}>
                <img
                  src={product.img}
                  alt={product.name}
                  className={styles.img}
                />
              </div>
              <div className={styles.info}>
                <h4 className={styles.name}>{product.name}</h4>
                <div className={styles.desc}>
                  <p>{product.desc}</p>
                </div>
              </div>
            </div>
          ))}
        </div>

        <div style={{ height: "100px" }}></div>
      </div>
    </div>
  );
};

export default Biscuits;
